@push('scripts')
<script>
    function library(data){
        return {
            data: data,
            error: '',
            loading: {},   // topicId -> bool
            results: {},   // topicId -> { resources, google_url, source }

            isLoading(id){ return !!this.loading[id]; },

            async findPdfs(topicId){
                this.error = '';
                this.loading = { ...this.loading, [topicId]: true };
                try {
                    const res = await fetch('{{ route('library.find') }}', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json', 'X-CSRF-TOKEN': document.querySelector('meta[name=csrf-token]').content },
                        body: JSON.stringify({ topic_id: topicId })
                    });
                    if (!res.ok) throw new Error('request failed');
                    const json = await res.json();
                    this.results = {
                        ...this.results,
                        [topicId]: {
                            resources: json.resources || [],
                            google_url: json.google_url || '#',
                            source: json.source || 'google'
                        }
                    };
                } catch(e){
                    this.error = 'Could not search for PDFs right now. Please try again.';
                } finally {
                    this.loading = { ...this.loading, [topicId]: false };
                    this.$nextTick(renderIcons);
                }
            }
        };
    }
</script>
@endpush
